INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-8b44517b-moex-00097', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '有關勞動基準法之退休，下列敘述何者正確？', '["工作25年以上者，不論年齡為何皆可退休", "工作10年以上或年滿60歲者，即可退休", "年滿65歲，即須退休不得再工作", "對於擔任具有危險、堅強體力等特殊性質之工作者，最晚55歲即應退休"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00098', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '選擇一次請領老年給付者，其平均月投保薪資之計算，下列何者正確？', '["按其退保之當月起前6個月之實際月投保薪資平均計算", "按其退保之當月起前20個月之實際月投保薪資平均計算", "按其退保之當月起前36個月之實際月投保薪資平均計算", "按其退保之當月起前60個月之實際月投保薪資平均計算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00099', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '被保險人或被保險人為身心障礙者權益保障法所定之身心障礙者，經評估為終身無工作能力者，而請領失 能年金給付，其得請求之失能年金最少為多少元？', '["3千元", "4千元", "5千元", "6千元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00100', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列何者非勞工保險條例所規定之給付內容？', '["育嬰給付", "生育給付", "醫療給付", "老年給付"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "744577c83c13", "answer_pdf_sha1": "682235d76532", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00101', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列文句「」中的成語用法，何者正確？', '["當一個人做事「行不由徑」，信用和形象都已被打折扣", "她講話總是「拾人牙慧」，充滿個人獨特的想法與見解", "上司若為人正直，行事端正，相信下屬也會「群起效尤」", "工作要先計畫周全再開始執行，才能收「事半功倍」之效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00102', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列選項句中的「窮」字，何者意義與其他三者不同？', '["明經博覽，無不「窮」究", "君子固「窮」，小人窮斯濫矣", "兩家子孫各長大，他年「窮」達毋相忘", "多有之者富，少有之者貧，至無有者「窮」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00103', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列情境語句，何者使用錯誤？', '["那雙「骨碌碌」的眼睛轉啊轉，不知在打什麼主意", "芭蕾舞者「活跳跳」的表演，看得觀眾都目不轉睛", "吃完這碗湯麵後，全身「熱呼呼」的，真是舒服啊", "此刻小張的心緒一定是「亂紛紛」的，別打擾他了"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00104', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列文句「」中的成語，運用恰當的是：', '["太魯閣風景「美輪美奐」，吸引遊客們駐足觀賞", "對於公司未來的發展，千萬不可「目無全牛」胡亂想像", "懲處違法亂紀的「始作俑者」，才能達到殺雞儆猴的效果", "夫妻之間「相敬如賓」，往往會讓旁人以為他們感情不好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00105', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列文句「」內的成語，何者替換成語後，文意不變？', '["他長期研究植物，提出許多具「真知灼見」的論文／略陳管見", "這是一部非常精密儀器，務必「小心翼翼」地操作／謹言慎行", "你要認真工作，千萬不可「玩日愒歲」，貪圖享樂／年深月久", "思考必須靈活變通，不宜「刻舟求劍」，拘泥不化／膠柱鼓瑟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00106', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列文句，何者沒有冗贅字詞？', '["由於雞蛋的需求量大，難怪不得市場的價格始終居高不下", "我竭盡所能地大聲哭著，但是到後來，卻聽不到自己的哭聲", "入夜後風雨仍然持續很大，一團朦朧的亮光卻已然在斜斜上空升起", "泰雅人的山田，大多數多在山坡、谷底，遠離部落，往返通常十分費時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
